 LinceAggiornamentoFile, Customer.[Updated Type] AS LinceTipoEvasione, Customer.[Due Date] AS LinceDataEvasione, Customer.[Internal Valuation], Customer.[Valuation Date], Customer.[Business E-Mail], LandedCost.[landed Cost], [pairsSold]*([landed cost]) AS EstimatedLandedCostOnSold, [ValueSold]-[pairsSold]*([landed cost]) AS EstimatedMargin, [valuesold]*[provvigioneagente]/100 AS EstimatedCommissionSalesPerson, [valuesold]*[provvigionecapozona]/100 AS EstimatedCommissionArewManager, [valuesold]*[provvigionesoggetto1]/100 AS EstimatedCommissionSubject1, [valuesold]*[provvigionesoggetto2]/100 AS EstimatedCommissionSubject2, [valuesold]*[provvigionesoggetto3]/100 AS EstimatedCommissionSubject3, [valuesold]*[provvigionesoggetto4]/100 AS EstimatedCommissionSubject4, [EstimatedMargin]-[EstimatedCommissionSalesPerson]-[EstimatedCommissionArewManager]-[EstimatedCommissionSubject1]-[EstimatedCommissionSubject2]-[EstimatedCommissionSubject3]-[EstimatedCommissionSubject4] AS EstimatedSecondMargin, Item.[Country_Region of Origin Code], DatiCarryOverESMU.[Sold Out], DatiCarryOverESMU.[Sold Out Date], DatiCarryOverESMU.[Sales_Purchase Status Date], Customer.[Fax No_], Val([Authorized Stores Number]) AS PuntiVendita, IIf([Store Distribution]=3,"3-Dept.Store",IIf([Store Distribution]=2,"2-Indipendent",IIf([Store Distribution]=1,"1-Chain","0-UNK"))) AS StoreDistribution, IIf([Store Image]=4,"4-Commodity",IIf([Store Image]=3,"3-Standard",IIf([Store Image]=2,"2-Premium",IIf([Store Image]=1,"1-Image","0-UNK")))) AS StoreImage, IIf([Store Type]=3,"3-Footwear",IIf([Store Type]=2,"2-Apparel-Footwear-Accessories",IIf([Store Type]=1,"1-Apparel-Footwear","0-UNK"))) AS StoreType, Customer.[Various References], Customer.[Home Page], Customer.[Quality Control], Customer.[Old Febos No_], Customer.[Old Bridge No_], [qSoloVend-step1].[Transport Reason Code], [qSoloVend-step1].TransportReasonCodeDescription, [qSoloVend-step1].[Location Code], [qSoloVend-step1].[Shipping Agent Code], [qSoloVend-step1].[Shipping Agent Service Code], [qSoloVend-step1].[Date Reservation], [qSoloVend-step1].[Fast Shipping], [qSoloVend-step1].ShipToGeographicalZone2, [Geographical Zone_2].Description AS ShipToGeographicalZone2Description, [qSoloVend-step1].ShipTpCountryRegionCode, Customer.[Payment Method Code] AS [Customer Payment Method], Customer.[Payment Terms Code] AS [Customer Payment Terms], [qSoloVend-step1].CommissionGroupCodeOrder, Customer.[Commission Group Code] AS CommissionGroupCodeCustomer, Customer.[VAT Bus_ Posting Group] AS [VAT Bus_ Posting Group_Customer], Customer.[Gen_ Bus_ Posting Group] AS [Gen_ Bus_ Posting Group_Customer], Customer.[Customer Posting Group] AS [Customer Posting Group_Customer], [qSoloVend-step1].[Special Requests], [qSoloVend-step1].[Purchase Group], [qSoloVend-step1].[Distribution Channel], Item.Manufacturer, Vendor_1.Name AS ManufacturerName, Item.[Advertising Material], Customer.[Credit Manager], Customer.[commercial manager], Customer.[EAC Labels], [qSoloVend-step1].GeographicalZoneFromOrder, [qSoloVend-step1].GeographicalZoneDescriptionFromOrder, [qSoloVend-step1].[Budget Area], DatiCarryOverESMU.[Future Carry Over], Customer.[Sovracollo Completo], Customer.[Authorized Stores Number]
FROM ((((((((((([qSoloVend-step1] INNER JOIN Item ON [qSoloVend-step1].Article = Item.No_) INNER JOIN [Variable Code] ON ([qSoloVend-step1].ColorCode = [Variable Code].[Variable Code]) AND (Item.[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group])) LEFT JOIN Customer ON [qSoloVend-step1].CustomerCode = Customer.No_) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) INNER JOIN DatiCarryOverESMU ON ([qSoloVend-step1].Article = DatiCarryOverESMU.[Model Item No_]) AND ([qSoloVend-step1].[Constant Variable Code] = DatiCarryOverESMU.[Variable Code 01])) LEFT JOIN [MustBuy-ArticoloColore] ON ([qSoloVend-step1].[Constant Variable Code] = [MustBuy-ArticoloColore].[Variable Code 01]) AND ([qSoloVend-step1].Article = [MustBuy-ArticoloColore].[Model Item No_])) LEFT JOIN [Geographical Zone] ON [qSoloVend-step1].[Geographical Zone] = [Geographical Zone].Code) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON [qSoloVend-step1].[Geographical Zone 2] = [Geographical Zone_1].Code) LEFT JOIN [Geographical Zone] AS [Geographical Zone_2] ON [qSoloVend-step1].ShipToGeographicalZone2 = [Geographical Zone_2].Code) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_) LEFT JOIN LandedCost ON [qSoloVend-step1].Article = LandedCost.No_) LEFT JOIN CrossReferenceCliente ON ([qSoloVend-step1].Article = CrossReferenceCliente.[Model Item No_]) AND ([qSoloVend-step1].[Constant Variable Code] = CrossReferenceCliente.[Constant Variable Code]) AND ([qSoloVend-step1].[Bill-to Customer No_] = CrossReferenceCliente.[Cross-Reference Type No_]);

